#include <vector>
#include <algorithm>
#include <cmath>

using namespace std;

long long solve(vector<long long> nums) {
    int n = nums.size();
    vector<long long> sorted_abs;
    for (long long num : nums) {
        sorted_abs.push_back(abs(num));
    }
    sort(sorted_abs.begin(), sorted_abs.end());
    long long count = 0;
    for (int j = 1; j < n; ++j) {
        long long target = sorted_abs[j];
        long long x_min = (target + 1) / 2;
        auto it = lower_bound(sorted_abs.begin(), sorted_abs.begin() + j, x_min);
        count += (j - (it - sorted_abs.begin()));
    }
    return count;
}
